def median(l: list):
    """Return median of elements in the list l.
    >>> median([3, 1, 2, 4, 5])
    3
    >>> median([-10, 4, 6, 1000, 10, 20])
    15.0
    """
    n = len(l)
    if n == 1:
        return l[0]
    elif n == 2:
        if l[0] > l[1]:
            return l[0]
        else:
            return l[1]
    else:
        sortedL = quicksort(l)
        mid = n // 2
        if (n % 2):
            # Odd
            return sortedL[mid]
        else:
            # Even
            return 0.5 * (sortedL[mid-1] + sortedL[mid])

